const items = $input.all();
const response = items[0].json;

let content = '';
if (response.message && response.message.content) {
  content = response.message.content;
} else if (response.response) {
  content = response.response;
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let strategyDSL = null;
let parseError = null;
try {
  strategyDSL = JSON.parse(content);
} catch (e) {
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      strategyDSL = JSON.parse(match[0]);
    } catch (e2) {
      parseError = `Failed to parse strategy JSON: ${e2.message}`;
    }
  } else {
    parseError = `No JSON found in proposer output: ${content.substring(0, 200)}`;
  }
}

return [{
  json: {
    strategyDSL,
    rawProposerOutput: content,
    parseError,
    proposerModel: 'qwen3',
    timestamp: new Date().toISOString()
  }
}];

const items = $input.all();
const data = items[0].json;

return [{
  json: {
    verdict: 'KILL',
    reason: 'Failed compilation',
    compilerErrors: data.errors || data.message || 'Unknown compiler error',
